        let mana = self.mana();
        let name = self.name().map(|x| x.to_string());
        let color = self.color();
        let inventory = self.inventory().map(|x| x.into_iter().collect());
        let friendly = self.friendly();
        let testarrayoftables = self.testarrayoftables().map(|x| x.iter().map(|t| t.unpack()).collect());
        let testarrayofstring = self.testarrayofstring().map(|x| x.iter().map(|s| s.to_string()).collect());
        let testarrayofstring2 = self.testarrayofstring2().map(|x| x.iter().map(|s| s.to_string()).collect());
