        let enemy = self.enemy().map(|x| alloc::boxed::Box::new(x.unpack()));
        let test = match self.test_type() {
          Any::NONE => AnyT::NONE,
          Any::Monster => AnyT::Monster(alloc::boxed::Box::new(self.test_as_monster().unwrap().unpack())),
          Any::TestSimpleTableWithEnum => AnyT::TestSimpleTableWithEnum(alloc::boxed::Box::new(self.test_as_test_simple_table_with_enum().unwrap().unpack())),
          Any::MyGame_Example2_Monster => AnyT::MyGameExample2Monster(alloc::boxed::Box::new(self.test_as_my_game_example2_monster().unwrap().unpack())),
          _ => AnyT::NONE,
        };
        let test4 = self.test4().map(|x| x.iter().map(|t| t.unpack()).collect());
        let test5 = self.test5().map(|x| x.iter().map(|t| t.unpack()).collect());
        let testnestedflatbuffer = self.testnestedflatbuffer().map(|x| x.into_iter().collect());
        let testempty = self.testempty().map(|x| alloc::boxed::Box::new(x.unpack()));
        let testbool = self.testbool();
        let testhashs32_fnv1 = self.testhashs32_fnv1();
